                            {
                                if (directories1.Contains(Path.GetFileNameWithoutExtension(files[i])))
                                {
                                    for (int i1 = 0; i1 < directories2.Length; i1++)
                                    {
                                        if (Path.GetFileNameWithoutExtension(directories2[i1]) == Path.GetFileNameWithoutExtension(files[i]) && Path.GetExtension(directories2[i1]) != Path.GetExtension(files[i]) && Path.GetExtension(directories2[i1]) != ".png" && Path.GetExtension(directories2[i1]) != ".jpg" && Path.GetExtension(directories2[i1]) != ".jpeg" && Path.GetExtension(directories2[i1]) != ".bmp")
                                        {
                                            File.Delete(directories2[i1]);
                                        }
                                    }
                                }
                                File.Copy(files[i], datafolder + @"\tools\RobloxAssetFixer\assets\" + Path.GetFileName(files[i]), true);
                            }
                            else
                            {
                                File.Copy(datafolder + @"\maps\" + listBox2.GetItemText(listBox2.SelectedItem), datafolder + @"\tools\RobloxAssetFixer\assets\" + Path.GetFileName(files[i]), true);
                            }
                        }
                    }
                }
                else
                {
                    if (cancelAsset) return;
                }

            }
            if (ReserveAssetIdForMap && isJoiningOrStudio == false && cancelAsset == false)
            {
                File.Copy(datafolder + @"\maps\" + listBox2.GetItemText(listBox2.SelectedItem), datafolder + @"\tools\RobloxAssetFixer\assets\" + placeid + ".rbxl", true);
            }
            progressBar1.Invoke(new Action(() => { progressBar1.Visible = false; }));
        }

        private string[] GetFileNamesWithoutExtension(string path)
        {
            if (Directory.Exists(path))
            {
                List<string> result = new List<string>();
                string[] files = Directory.GetFiles(path);
                foreach (string file in files)
                {
                    result.Add(Path.GetFileNameWithoutExtension(file));
                }
                return result.ToArray();
            }
            else
            {
                return new string[] { };
            }
        }

        private void ClearAssets()
        {
            statusText.Invoke(new Action(() => { statusText.Text = "Cleaning up assets..."; }));
            string[] files = Directory.GetFiles(datafolder + @"\tools\RobloxAssetFixer\assets");
            foreach (string file in files)
            {
                if (file.EndsWith("avatar.png") == false && file.EndsWith("gameicon.png") == false && file.EndsWith("headshot.png") == false)
                {
                    try
                    {
                        if (File.Exists(file))
                        {
                            File.Delete(file);
                        }
                    }
                    catch
                    {
                        //do nothing
                    }
                }
            }
        }

        private void ApplyTheme(Control controlorigin)
        {
            foreach (Control control in controlorigin.Controls)
            {
                if (control is TextBox || control is System.Windows.Forms.Button || control is ComboBox || control is ListBox || control is Panel || control is NumericUpDown || control is ListView)
                {
                    control.BackColor = Color.FromArgb(30, 30, 30);
                    control.ForeColor = Color.White;
                    if (control is TextBox)
                    {
                        (control as TextBox).BorderStyle = BorderStyle.FixedSingle;
                    }
                    else if (control is ListBox)
                    {
                        (control as ListBox).BorderStyle = BorderStyle.None;
                    }
                    else if (control is ComboBox)
                    {
                        (control as ComboBox).FlatStyle = FlatStyle.Flat;
                    }
                    else if (control is System.Windows.Forms.Button)
                    {
                        (control as System.Windows.Forms.Button).FlatStyle = FlatStyle.Flat;
                        (control as System.Windows.Forms.Button).FlatAppearance.BorderColor = Color.Black;
                    }
                    else if (control is Panel)
                    {
                        if (control.Controls.Count > 0)
                        {
                            ApplyTheme(control);
                        }
                    }
                    else if (control is NumericUpDown)
                    {
                        (control as NumericUpDown).BorderStyle = BorderStyle.FixedSingle;
                    }
                    else if (control is ListView)
                    {
                        (control as ListView).BorderStyle = BorderStyle.FixedSingle;
                    }
                }
            }
        }
