        private bool CheckForUpdates(bool useNewUpdateUrl)
        {
            if (useNewUpdateUrl)
            {
                try
                {
                    WebClient client = new WebClient();
                    Console.WriteLine("<INFO> Checking the version of the client and the server reports...");
                    string rawJSON = client.DownloadString(updateurl + @"/updates/version.json");
                    Newtonsoft.Json.Linq.JObject jObject = Newtonsoft.Json.Linq.JObject.Parse(rawJSON);

                    if ((string)jObject["launcherVersion"] != Properties.Settings.Default.version)
                    {
                        Console.WriteLine("<INFO> Update is available for the ReBlox Launcher!");
                        return true;
                    }
                    else
                    {
                        Console.WriteLine("<INFO> No update is available.");
                        return false;
                    }
                }
                catch
                {
                    return false;
                }
            }
            else
            {
                try
                {
                    WebClient client = new WebClient();
                    Console.WriteLine("<INFO> Checking the version of the client and the server reports...");
                    if (client.DownloadString(updateurl + @"/version.txt") != Properties.Settings.Default.version)
                    {
                        Console.WriteLine("<INFO> Update is available for the ReBlox Launcher!");
                        return true;
                    }
                    else
                    {
                        Console.WriteLine("<INFO> No update is available.");
                        return false;
                    }
                }
                catch
                {
                    return false;
                }
            }
        }

        private void Form1_Load(object sender, EventArgs e)
        {
            if (Debugger.IsAttached)
            {
                Control.CheckForIllegalCrossThreadCalls = false;
            }
            ServicePointManager.SecurityProtocol = SecurityProtocolType.Tls12;
            label2.Text = "v" + Properties.Settings.Default.version;
            string[] args = Environment.GetCommandLineArgs();
            for (int i = 0; i < args.Length; i++)
            {
                if (args[i] == "-datafolder")
                {
                    if (Directory.Exists(args[i + 1]))
                    {
                        datafolder = args[i + 1];
                        i++;
                    }
                    else
                    {
                        MessageBox.Show("This is an invalid data folder! Please try a different data folder or rename it without spaces!", aprilFools ? "Sodikm Premium" : "ReBlox", MessageBoxButtons.OK, MessageBoxIcon.Error);
                    }
                }
                else if (args[i] == "--saveKeys")
                {
                    using (RSACryptoServiceProvider RSA = new RSACryptoServiceProvider())
                    {
                        byte[] publicdata = RSA.ExportCspBlob(false);
                        byte[] privatedata = RSA.ExportCspBlob(true);
                        File.WriteAllText(datafolder + @"\public.txt", Convert.ToBase64String(publicdata));
                        File.WriteAllText(datafolder + @"\private.txt", Convert.ToBase64String(privatedata));
                        using (TextWriter w = File.CreateText(datafolder + @"\private.pem"))
                        {
                            ExportPrivateKey(RSA, w);
                        }
                        MessageBox.Show("BLOB created", aprilFools ? "Sodikm Premium" : "ReBlox", MessageBoxButtons.OK, MessageBoxIcon.Question);
                    }
                }
                else if (args[i] == "--useSystemNode")
                {
                    useSystemNode = true;
                }
                else if (args[i] == "-launch")
                {
                    if (Directory.Exists(datafolder + @"\clients\" + args[i + 1]))
                    {
                        launchershortcut = true;
                        new LaunchScreen(args[i + 1], datafolder, useSystemNode).Show();
                        i++;
                    }
                    else
                    {
                        MessageBox.Show("This is an invalid version!", aprilFools ? "Sodikm Premium" : "ReBlox", MessageBoxButtons.OK, MessageBoxIcon.Error);
                    }
                }
                else if (args[i] == "-updateUrl")
                {
                    if (ValidateUrlWithUrlCreate(args[i + 1], out _))
                    {
                        updateurl = args[i + 1];
                    }
                    else
                    {
                        Console.WriteLine("<WARN> The URL for the update server is not valid! Reverting to the default...");
                    }
                }
                else if (args[i] == "--installCA")
                {
                    if (File.Exists(Path.GetDirectoryName(Application.ExecutablePath) + @"\ca.pem"))
                    {
                        if (IsAdministrator())
                        {
                            X509Store store = new X509Store(StoreName.Root, StoreLocation.LocalMachine);
                            store.Open(OpenFlags.ReadOnly);
                            X509Certificate2 x509 = new X509Certificate2(X509Certificate2.CreateFromCertFile(Path.GetDirectoryName(Application.ExecutablePath) + @"\ca.pem"));
                            var certificates = store.Certificates.Find(X509FindType.FindByThumbprint, x509.Thumbprint, false);
                            if (certificates != null && certificates.Count > 0)
                            {
                                caInstalled = true;
                            }
                            else
                            {
                                Console.WriteLine("<INFO> Installing the CA Certificate");
                                store.Close();
                                store.Open(OpenFlags.ReadWrite);
                                store.Add(x509);
                                store.Close();
                                caInstalled = true;
                            }
                            x509.Dispose();
                        }
                        else
                        {
                            Console.WriteLine("<INFO> Administrator is required to install the certificate, skipping...");
                        }
                    }
                    else
                    {
                        Console.WriteLine("<INFO> The CA cert doesn't exist, skipping...");
                    }
                }
                else if (args[i] == "--editHosts")
                {
                    if (IsAdministrator())
                    {
                        try
                        {
                            if (smartHostDetector() == false && (WineDetector.IsRunningOnWine() == false || linuxAsWindows == true))
                            {
                                smartHostEdit();
                            }
                        }
                        catch (Exception err)
                        {
                            MessageBox.Show("An error has occurred while editing the hosts file, please look in logs for more details.");
                            Console.WriteLine("<ERROR> An error has occurred while attempting to edit the hosts file:" + err);
                        }
                    }
                    else
                    {
                        Console.WriteLine("<WARN> You don't have administrator permission to edit the hosts file! Please run the launcher as administrator with this argument to edit the hosts file!");
                    }
                }
                else if (args[i] == "--aprilFools")
                {
                    aprilFools = true;
                    pictureBox2.Image = Properties.Resources.resources_logo;
                    pictureBox2.Visible = true;
                    this.Text = "Sodikm Premium";
