            {
                splashscreen = new SplashScreen(datafolder);
                splashscreen.Show();
            }

            if (File.Exists(Path.GetDirectoryName(Application.ExecutablePath) + @"\ca.pem"))
            {
                X509Store store = new X509Store(StoreName.Root, StoreLocation.LocalMachine);
                store.Open(OpenFlags.ReadOnly);
                X509Certificate2 x509 = new X509Certificate2(X509Certificate2.CreateFromCertFile(Path.GetDirectoryName(Application.ExecutablePath) + @"\ca.pem"));
                var certificates = store.Certificates.Find(X509FindType.FindByThumbprint, x509.Thumbprint, false);
                if (certificates != null && certificates.Count > 0 || Properties.Settings.Default.CADontShow)
                {
                    Console.WriteLine("<INFO> The CA cert that is checked is already installed on the computer");
                    x509.Dispose();
                    caInstalled = true;
                }
                else
                {
                    var result = MessageBox.Show("Wanna install the CA certificate of ReBlox? This is not required (unless you're planning to use 2018+ clients), but this can make connection secure and be able to download assets/decals from the browser via domain name. Pressing Cancel will not show this ever again, however you can still install it in settings at anytime.", "CA Certificate", MessageBoxButtons.YesNoCancel, MessageBoxIcon.Question);
                    if (result == DialogResult.Yes)
                    {
                        if (IsAdministrator())
                        {
                            Console.WriteLine("<INFO> Installing the CA Certificate");
                            store.Close();
                            store.Open(OpenFlags.ReadWrite);
                            store.Add(x509);
                            store.Close();
                            x509.Dispose();
                            caInstalled = true;
                        }
                        else
                        {
                            try
                            {
                                ProcessStartInfo ps = new ProcessStartInfo() { UseShellExecute = true, FileName = Application.ExecutablePath, Verb = "runas", Arguments = "--installCA" };
                                Process.Start(ps);
                                Application.Exit();
                            }
                            catch
                            {
                                MessageBox.Show("Something went wrong while trying to run the launcher as administrator! Please run the launcher manually as administrator.", aprilFools ? "Sodikm Premium" : "ReBlox", MessageBoxButtons.OK, MessageBoxIcon.Error);
                            }
                        }
                    }
                    else if (result == DialogResult.Cancel)
                    {
                        Properties.Settings.Default.CADontShow = true;
                        Properties.Settings.Default.Save();
                    }
                }
            }
            Thread thread = new Thread(() =>
            {
                if (CheckForInternetConnection())
                {
                    try
                    {
                        if (CheckForUpdates(true))
                        {
                            label33.Invoke(new Action(() => { label33.Visible = true; }));
                            button6.Invoke(new Action(() => { button6.Visible = true; }));
                            label40.Invoke(new Action(() => { label40.Text = "We found a new update for you!"; }));
                        }
                        else
                        {
                            label40.Invoke(new Action(() => { label40.Text = "No new update is available."; }));
                        }
                    }
                    catch (Exception e)
                    {
                        Console.WriteLine("<ERROR> Something when wrong while trying to check for updates! Look in the error for details!\r\n" + e);
                    }
                }
            });
            thread.TrySetApartmentState(ApartmentState.STA);
            thread.Start();
            if (launchershortcut == false) Initialize();
        }

        public void smartHostEdit()
        {
            if (IsAdministrator())
            {
                string[] urls = new string[] { "reblox.zip", "www.reblox.zip", "api.reblox.zip", "assetgame.reblox.zip", "auth.reblox.zip", "assetdelivery.reblox.zip", "develop.reblox.zip", "clientsettings.api.reblox.zip", "gamepersistence.reblox.zip", "avatar.reblox.zip", "thumbnails.reblox.zip", "groups.reblox.zip", "clientsettingscdn.reblox.zip", "catalog.reblox.zip", "apis.reblox.zip", "games.reblox.zip", "friends.reblox.zip", "economy.reblox.zip", "badges.reblox.zip", "users.reblox.zip", "locale.reblox.zip", "versioncompatibility.api.reblox.zip", "data.reblox.zip", "abtesting.reblox.zip", "inventory.reblox.zip", "premiumfeatures.reblox.zip", "chat.reblox.zip", "gameinternationalization.reblox.zip", "publish.reblox.zip", "translationroles.reblox.zip", "voice.reblox.zip" };
                string[] hosts = File.ReadAllLines(@"C:\Windows\System32\drivers\etc\hosts");

                List<string> neededEdits = new List<string>();
                neededEdits.AddRange(urls);
                for (int i = 0; i < hosts.Length; i++)
                {
                    for (int x = 0; x < urls.Length; x++)
                    {
                        if (hosts[i] == "127.0.0.1 " + urls[x])
                        {
                            neededEdits.Remove(urls[x]);
                        }
                    }
                }

                string convertedString = "\r\n127.0.0.1 " + string.Join("\r\n127.0.0.1 ", neededEdits);

                File.AppendAllText(@"C:\Windows\System32\drivers\etc\hosts", convertedString);
            }
        }

        public void smartHostRemove()
