                File.WriteAllText(@"C:\Windows\System32\drivers\etc\hosts", hosts);
            }
        }

        public bool smartHostDetector()
        {
            string[] urls = new string[] { "reblox.zip", "www.reblox.zip", "api.reblox.zip", "assetgame.reblox.zip", "auth.reblox.zip", "assetdelivery.reblox.zip", "develop.reblox.zip", "clientsettings.api.reblox.zip", "gamepersistence.reblox.zip", "avatar.reblox.zip", "thumbnails.reblox.zip", "groups.reblox.zip", "clientsettingscdn.reblox.zip", "catalog.reblox.zip", "apis.reblox.zip", "games.reblox.zip", "friends.reblox.zip", "economy.reblox.zip", "badges.reblox.zip", "users.reblox.zip", "locale.reblox.zip", "versioncompatibility.api.reblox.zip", "data.reblox.zip", "abtesting.reblox.zip", "inventory.reblox.zip", "premiumfeatures.reblox.zip", "chat.reblox.zip", "gameinternationalization.reblox.zip", "publish.reblox.zip", "translationroles.reblox.zip", "voice.reblox.zip" };
            string[] hosts = File.ReadAllLines(@"C:\Windows\System32\drivers\etc\hosts");

            List<string> neededEdits = new List<string>();
            neededEdits.AddRange(urls);
            for (int i = 0; i < hosts.Length; i++)
            {
                for (int x = 0; x < urls.Length; x++)
                {
                    if (hosts[i] == "127.0.0.1 " + urls[x])
                    {
                        neededEdits.Remove(urls[x]);
                    }
                }
            }

            string convertedString = "\r\n127.0.0.1 " + string.Join("\r\n127.0.0.1 ", neededEdits);

            if (neededEdits.Count > 0)
            {
                return false;
            }
            else
            {
                return true;
            }
        }

        public void SearchNetworks(bool limitServersByLauncherVersion = false)
        {
            UdpClient clientUdpClient = null;
            try
            {
                clientUdpClient = ServerUtils.GetClient(0);
                IPEndPoint ServerEp = new IPEndPoint(IPAddress.Any, 0);
                byte[] requestData = Encoding.UTF8.GetBytes("ping");
                byte[] ServerResponseData = null;

                clientUdpClient.Client.ReceiveTimeout = 10000;
                clientUdpClient.Client.SendTimeout = 10000;
                clientUdpClient.JoinMulticastGroup(IPAddress.Parse("231.100.2.3"));
                clientUdpClient.Send(requestData, requestData.Length, new IPEndPoint(IPAddress.Parse("231.100.2.3"), 50358));
                label35.Invoke(new Action(() => { label35.Visible = true; }));

                while (searchingNetwork == true)
                {
                    ServerResponseData = clientUdpClient.Receive(ref ServerEp);
                    string ServerResponse;
                    if (ServerResponseData != null)
                    {
                        ServerResponse = Encoding.UTF8.GetString(ServerResponseData);

                        string[] responsesplit = ServerResponse.Split(new char[] { '|' }, 7);

                        if (limitServersByLauncherVersion == false || (limitServersByLauncherVersion == true && Properties.Settings.Default.version == responsesplit[3]))
                        {
                            Console.WriteLine("<INFO> Found server: " + ServerEp.Address.ToString());
                            ListViewItem item = null;
                            listView1.Invoke(new Action(() => { item = listView1.Items.Add(responsesplit[6]); }));
                            item.SubItems.Add(responsesplit[1]);
                            item.SubItems.Add(responsesplit[2]);
                            item.SubItems.Add(responsesplit[3]);
                            item.SubItems.Add(responsesplit[4]);
                            item.SubItems.Add(ServerEp.Address.ToString());
                        }
                    }

                }
            }
            catch (SocketException)
            {
                label35.Invoke(new Action(() => { label35.Visible = false; }));
                if (clientUdpClient != null)
                {
                    clientUdpClient.DropMulticastGroup(IPAddress.Parse("231.100.2.3"));
                }
                searchingNetwork = false;
            }
            catch (Exception e)
            {
                Console.WriteLine("<ERROR> Something went wrong while looking for servers! " + e);
            }


        }

