                                }
                                else
                                {
                                    ps1.Arguments = "index.js -username=" + (guestMode ? guestUsername : Properties.Settings.Default.username) + " -userid=" + (guestMode ? guestUserId : (Properties.Settings.Default.LongUserIdExperiment ? Properties.Settings.Default.UserIdLong : Properties.Settings.Default.UserId)) + (Properties.Settings.Default.EnableBadges ? "" : " -disableBadges") + (Properties.Settings.Default.EnableDataStore ? "" : " -disableDataStore") + (Properties.Settings.Default.EnableFollowing ? "" : " -disableFollowing") + (Properties.Settings.Default.EnableFriendships ? "" : " -disableFriendships") + (Properties.Settings.Default.EnableOwnedAssets ? "" : " -disableOwnedAssets") + (guestMode == false && Properties.Settings.Default.AccountOver13 ? "" : " -accountUnder13") + " -robux=" + Properties.Settings.Default.Robux + (guestMode ? "" : " --allowGetCurrentUser") + (useOldAssetFormat ? " -disableNewSignatureAsset" : "") + (useOldSignature ? " -disableNewSignature" : "") + (Properties.Settings.Default.UploadFilesAllowed ? " --allowUploadingFiles" : "");
                                }
                                ps1.WindowStyle = ProcessWindowStyle.Hidden;
                                ps1.WorkingDirectory = datafolder + @"\tools\RobloxAssetFixer";

                                if ((guestMode ? guestUsername : Properties.Settings.Default.username).Length > 2 && (guestMode ? guestUserId : (Properties.Settings.Default.LongUserIdExperiment ? Properties.Settings.Default.UserIdLong : Properties.Settings.Default.UserId)) > 0 || guestMode == true)
                                {

                                    if (Properties.Settings.Default.UsePatchInStudio)
                                    {
                                        if (IsNodeFromAppRunning() == false)
                                        {
                                            Process test = Process.Start(ps1);
                                            launchingClient = false;
                                            button1.Invoke(new Action(() => { button1.Enabled = true; }));
                                            button2.Invoke(new Action(() => { button2.Enabled = true; }));
                                            button3.Invoke(new Action(() => { button3.Enabled = true; }));
                                            button27.Invoke(new Action(() => { button27.Enabled = true; }));
                                            statusText.Invoke(new Action(() => { statusText.Text = "Waiting for node server to start..."; }));
                                            test.OutputDataReceived += new DataReceivedEventHandler(async (object sender1, DataReceivedEventArgs e1) =>
                                            {
                                                if (e1.Data != null)
                                                {
                                                    if (logNodeServer) Console.WriteLine(e1.Data);
                                                    if (e1.Data.Contains("<INFO> Started a HTTP") || e1.Data.Contains("Http Server started"))
                                                    {
                                                        setupAvatarOnServer();
                                                        statusText.Invoke(new Action(() => { statusText.Text = (useNewRoblox ? "Starting Roblox..." : "Starting ROBLOX..."); }));
                                                        Process roblox = Process.Start(ps);
                                                        roblox.EnableRaisingEvents = true;
                                                        roblox.Exited += Roblox_Exited;
                                                        test.CancelOutputRead();
                                                        await Task.Delay(3000);
                                                        statusText.Invoke(new Action(() => { statusText.Visible = false; }));
                                                        statusText.Invoke(new Action(() => { statusText.Text = ""; }));
                                                    }
                                                }
                                            });
                                            test.BeginOutputReadLine();
                                        }
                                        else
                                        {
                                            setupAvatarOnServer();
                                            statusText.Invoke(new Action(() => { statusText.Text = (useNewRoblox ? "Starting Roblox..." : "Starting ROBLOX..."); }));
                                            button1.Invoke(new Action(() => { button1.Enabled = true; }));
                                            button2.Invoke(new Action(() => { button2.Enabled = true; }));
                                            button3.Invoke(new Action(() => { button3.Enabled = true; }));
                                            button27.Invoke(new Action(() => { button27.Enabled = true; }));
                                            launchingClient = false;
                                            Process roblox = Process.Start(ps);
                                            roblox.EnableRaisingEvents = true;
                                            roblox.Exited += Roblox_Exited;
                                            await Task.Delay(3000);
                                            statusText.Invoke(new Action(() => { statusText.Visible = false; }));
                                            statusText.Invoke(new Action(() => { statusText.Text = ""; }));
                                        }
                                    }
                                    else
                                    {
                                        launchingClient = false;
                                        button1.Invoke(new Action(() => { button1.Enabled = true; }));
                                        button2.Invoke(new Action(() => { button2.Enabled = true; }));
                                        button3.Invoke(new Action(() => { button3.Enabled = true; }));
                                        button27.Invoke(new Action(() => { button27.Enabled = true; }));
                                        statusText.Invoke(new Action(() => { statusText.Text = (useNewRoblox ? "Starting Roblox..." : "Starting ROBLOX..."); }));
                                        Process roblox = Process.Start(ps);
                                        roblox.EnableRaisingEvents = true;
                                        roblox.Exited += Roblox_Exited;
                                        await Task.Delay(3000);
                                        statusText.Invoke(new Action(() => { statusText.Visible = false; }));
                                        statusText.Invoke(new Action(() => { statusText.Text = ""; }));
                                    }

                                }
                                else
                                {
                                    MessageBox.Show("A valid username or UserId is required!", aprilFools ? "Sodikm Premium" : "ReBlox", MessageBoxButtons.OK, MessageBoxIcon.Error);
                                    button1.Invoke(new Action(() => { button1.Enabled = true; }));
                                    button2.Invoke(new Action(() => { button2.Enabled = true; }));
                                    button3.Invoke(new Action(() => { button3.Enabled = true; }));
                                    button27.Invoke(new Action(() => { button27.Enabled = true; }));
                                    launchingClient = false;
                                    await Task.Delay(3000);
                                    statusText.Invoke(new Action(() => { statusText.Visible = false; }));
                                    statusText.Invoke(new Action(() => { statusText.Text = ""; }));
                                }

                            }
                        }
                        catch (Exception e1)
                        {
                            launchingClient = false;
                            MessageBox.Show("Something went wrong while trying to launch Studio, please look in the error message for details: " + e1.Message, aprilFools ? "Sodikm Premium" : "ReBlox", MessageBoxButtons.OK, MessageBoxIcon.Error);
                            Console.WriteLine("<ERROR> Something went wrong when attempting to launch Studio! Please look in the error below and report it to the developer if it's launcher-sided!\n" + e1.Message + "\nStack Trace:\n" + e1.StackTrace);
                            await Task.Delay(3000);
                            statusText.Invoke(new Action(() => { statusText.Visible = false; }));
                            statusText.Invoke(new Action(() => { statusText.Text = ""; }));
                        }
                    });
                    thread.TrySetApartmentState(ApartmentState.MTA);
                    thread.Start();
                }
                else
                {
                    MessageBox.Show("You need to select a character in Customize!", aprilFools ? "Sodikm Premium" : "ReBlox", MessageBoxButtons.OK, MessageBoxIcon.Error);
                }
            }
            else
            {
                MessageBox.Show("A client must be selected to be able to run!", aprilFools ? "Sodikm Premium" : "ReBlox", MessageBoxButtons.OK, MessageBoxIcon.Error);
            }
        }


        private void Roblox_Exited(object sender, EventArgs e)
        {
            if (exitingClient == false && launchingClient == false)
            {
                Process[] processesr = Process.GetProcessesByName("RobloxStudioBeta");
                Process[] processesr1 = Process.GetProcessesByName("RobloxPlayerBeta");
                Process[] processesr2 = Process.GetProcessesByName("RCCService");
                if (processesr.Length <= 0 && processesr1.Length <= 0 && processesr2.Length <= 0)
                {
                    //I know it's the second time, but a race condition could happen if we don't put an if here.
                    if (exitingClient == false && launchingClient == false)
                    {
                        exitingClient = true;
                        if (hostVersion != "") { if (Directory.Exists(datafolder + @"\clients\" + hostVersion + @"\RCCService")) { if (File.Exists(datafolder + @"\clients\" + hostVersion + @"\RCCService\gameserver.txt")) { File.Delete(datafolder + @"\clients\" + hostVersion + @"\RCCService\gameserver.txt"); } } }
                        hostVersion = "";
                        button1.Invoke(new Action(() => { button1.Enabled = false; }));
                        button2.Invoke(new Action(() => { button2.Enabled = false; }));
                        button3.Invoke(new Action(() => { button3.Enabled = false; }));
                        button27.Invoke(new Action(() => { button27.Enabled = false; }));
                        statusText.Invoke(new Action(() => { statusText.Visible = true; }));
                        Process[] processes = Process.GetProcessesByName("node");
                        if (processes.Length > 0)
                        {
                            foreach (Process process in processes)
                            {
                                if (process.MainModule.FileName == datafolder + @"\tools\node\node.exe")
                                {
                                    Console.WriteLine("<INFO> Shutting down the node server");
                                    statusText.Invoke(new Action(() => { statusText.Text = "Closing node server..."; }));
                                    process.Kill();
                                }
                            }
                        }
                        processes = Process.GetProcessesByName("IPForwarder");
                        if (processes.Length > 0)
                        {
                            foreach (Process process in processes)
                            {
                                Console.WriteLine("<INFO> Shutting down IPForwarder");
                                statusText.Invoke(new Action(() => { statusText.Text = "Closing IPForwarder..."; }));
                                process.Kill();
                            }
                        }

                        if (Properties.Settings.Default.ClearTemp)
                        {
                            Console.WriteLine("<INFO> Clearing ROBLOX's temporary files");
                            statusText.Invoke(new Action(() => { statusText.Text = "Clearing temp files..."; }));
                            if (Directory.Exists(Path.GetTempPath() + "Roblox")) Directory.Delete(Path.GetTempPath() + "Roblox", true);
                        }
                        RemoveGameFiles();
                        ClearAssets();
                        sha1assets.Clear();
                        ServerUtils.StopListServer();
                        if (guestMode)
                        {
                            guestUsername = "Guest " + RandomNumber(0, 10000);
                            guestUserId = RandomNumber(int.MinValue, 0);
                            textBox4.Text = guestUserId.ToString();
                            textBox5.Text = guestUsername;
                        }
                        button1.Invoke(new Action(() => { button1.Enabled = true; }));
                        button2.Invoke(new Action(() => { button2.Enabled = true; }));
                        button3.Invoke(new Action(() => { button3.Enabled = true; }));
                        button27.Invoke(new Action(() => { button27.Enabled = true; }));
                        statusText.Invoke(new Action(() => { statusText.Visible = false; }));
                        exitingClient = false;
                    }
                }
            }
        }

        private void listBox1_SelectedIndexChanged(object sender, EventArgs e)
        {
            try
            {
                if (listBox1.SelectedIndex > -1)
                {
                    label5.Text = listBox1.GetItemText(listBox1.SelectedItem);
                    Properties.Settings.Default.lastselectedversion = listBox1.GetItemText(listBox1.SelectedItem);
                    Properties.Settings.Default.Save();
                    if (File.Exists(datafolder + @"\clients\" + listBox1.GetItemText(listBox1.SelectedItem) + @"\ReBlox.ini"))
                    {
                        string[] config = File.ReadAllLines(datafolder + @"\clients\" + listBox1.GetItemText(listBox1.SelectedItem) + @"\ReBlox.ini");
                        if (config[0] == "[Reblox]")
                        {
                            if (Properties.Settings.Default.DiscordRPC && client != null)
                            {
                                if (client.IsInitialized)
                                {
                                    client.SetPresence(new RichPresence()
                                    {
                                        Details = "v" + Properties.Settings.Default.version,
                                        State = "Viewing clients" + ((Properties.Settings.Default.lastselectedversion != "" && listBox1.Items.Contains(Properties.Settings.Default.lastselectedversion)) ? " (" + Properties.Settings.Default.lastselectedversion + ")" : ""),
                                        Assets = new Assets()
                                        {
                                            LargeImageKey = "rebloxicon"
                                        },
                                        Timestamps = client.CurrentPresence.HasTimestamps() ? client.CurrentPresence.Timestamps : Timestamps.Now
                                    });
                                }
                            }
                            placeid = -1;
                            UseJoinJSONLink = false;
                            useIPForwarder = false;
                            ReserveAssetIdForMap = false;
                            label24.Visible = false;
                            useNewRoblox = false;
                            useOldSignature = false;
                            useOldAssetFormat = false;
                            dontLoadMapFromArgument = false;
                            RCCService = false;
                            usedRCCService = false;
                            useOldGuestAvatar = false;
                            althostargument = "";
                            altjoinargument = "";
                            versionForRCCService = "";
                            for (int i = 0; i < config.Length; i++)
                            {
                                if (config[i].Trim().StartsWith("Description=\""))
                                {
                                    string[] splited = config[i].Trim().Split(new char[] { '=' }, 2);
                                    label6.Text = splited[1].Remove(0, 1).Remove(splited[1].Length - 2, 1);
                                }
                                else if (config[i].Trim().StartsWith("JoinArgument=\""))
                                {
                                    string[] splited = config[i].Trim().Split(new char[] { '=' }, 2);
                                    joinargument = splited[1].Remove(0, 1).Remove(splited[1].Length - 2, 1);
                                }
                                else if (config[i].Trim().StartsWith("HostArgument=\""))
                                {
                                    string[] splited = config[i].Trim().Split(new char[] { '=' }, 2);
                                    hostargument = splited[1].Remove(0, 1).Remove(splited[1].Length - 2, 1);
                                }
                                else if (config[i].Trim().StartsWith("AltJoinArgument=\""))
                                {
                                    string[] splited = config[i].Trim().Split(new char[] { '=' }, 2);
                                    altjoinargument = splited[1].Remove(0, 1).Remove(splited[1].Length - 2, 1);
                                }
                                else if (config[i].Trim().StartsWith("AltHostArgument=\""))
                                {
                                    string[] splited = config[i].Trim().Split(new char[] { '=' }, 2);
                                    althostargument = splited[1].Remove(0, 1).Remove(splited[1].Length - 2, 1);
                                }
                                else if (config[i].Trim().StartsWith("Version="))
                                {
                                    string[] splited = config[i].Trim().Split(new char[] { '=' }, 2);
                                    if (splited[1].Trim() != "")
                                    {
                                        label24.Visible = true;
                                        label24.Text = splited[1];
                                    }
                                    else
                                    {
                                        label24.Visible = false;
                                    }
                                }
                                else if (config[i].Trim() == "UseJoinScript=true")
                                {
                                    UseJoinJSONLink = true;
                                    label27.Visible = true;
                                    comboBox2.Visible = true;
                                    label32.Visible = true;
                                    comboBox3.Visible = true;
                                }
                                else if (config[i].Trim() == "UseJoinScript=false")
                                {
                                    UseJoinJSONLink = false;
                                    label27.Visible = false;
                                    comboBox2.Visible = false;
                                    label32.Visible = false;
                                    comboBox3.Visible = false;
                                }
                                else if (config[i].Trim() == "2018OverMessage=true")
                                {
                                    if (Properties.Settings.Default.UsePatchInStudio == false)
                                    {
                                        if (caInstalled)
                                        {
                                            MessageBox.Show("Note that RobloxAssetFixer is strongly recommended to be able to use this client property and login. You should turn on \"Use RobloxAssetFixer when opening in Studio mode\", located in Settings [If you're launching in Studio]", aprilFools ? "Sodikm Premium" : "ReBlox", MessageBoxButtons.OK, MessageBoxIcon.Warning);
                                        }
                                        else
                                        {
                                            button1.Enabled = false;
                                            button2.Enabled = false;
                                            button3.Enabled = false;
                                            MessageBox.Show("Note that RobloxAssetFixer is strongly recommended to be able to use this client property and login, the CA certificate is also required to be able to use 2018+ clients. You should turn on \"Use RobloxAssetFixer when opening in Studio mode\", located in Settings [If you're launching in Studio]", aprilFools ? "Sodikm Premium" : "ReBlox", MessageBoxButtons.OK, MessageBoxIcon.Warning);
                                        }
                                    }
                                    else
                                    {
                                        if (caInstalled == false)
                                        {
                                            button1.Enabled = false;
                                            button2.Enabled = false;
                                            button3.Enabled = false;
                                            MessageBox.Show("The CA certificate is required to be able to use 2018+ clients. You can install the CA certificate by going to Settings > Install CA.", aprilFools ? "Sodikm Premium" : "ReBlox", MessageBoxButtons.OK, MessageBoxIcon.Error);
                                        }
                                        else
                                        {
                                            if (launchingClient == false)
                                            {
                                                button1.Enabled = true;
                                                button2.Enabled = true;
                                                button3.Enabled = true;
                                            }
                                        }
                                    }
                                }
                                else if (config[i].Trim() == "UseIPForwarder=true")
                                {
                                    useIPForwarder = true;
                                }
                                else if (config[i].Trim() == "UseIPForwarder=false")
                                {
                                    useIPForwarder = false;
                                }
                                else if (config[i].Trim().StartsWith("PlaceId="))
                                {
                                    if (int.TryParse(config[i].Trim().Replace("PlaceId=", ""), out _) == true)
                                    {
                                        placeid = int.Parse(config[i].Trim().Replace("PlaceId=", ""));
                                    }
                                }
                                else if (config[i].Trim() == "UsePlaceAsAsset=true")
                                {
                                    if (placeid > -1)
                                    {
                                        ReserveAssetIdForMap = true;
                                    }
                                    else
                                    {
                                        MessageBox.Show("PlaceId is required for UsePlaceAsAsset", aprilFools ? "Sodikm Premium" : "ReBlox", MessageBoxButtons.OK, MessageBoxIcon.Error);
                                    }
                                }
                                else if (config[i].Trim() == "UsePlaceAsAsset=false")
                                {
                                    ReserveAssetIdForMap = false;
                                    placeid = -1;
                                }
                                else if (config[i].Trim() == "UseNewRobloxName=true")
                                {
                                    useNewRoblox = true;
                                }
                                else if (config[i].Trim() == "UseOldSignature=true")
                                {
                                    useOldSignature = true;
                                }
                                else if (config[i].Trim() == "UseOldAssetFormat=true")
                                {
                                    useOldAssetFormat = true;
                                }
                                else if (config[i].Trim() == "DontLoadMapFromArgument=true")
                                {
                                    dontLoadMapFromArgument = true;
                                }
                                else if (config[i].Trim() == "HasSecurityVulnerability=true")
                                {
                                    MessageBox.Show("This client version that you have selected appears to have security vulnerabilities, which could put your PC at risk! Please be careful when using this client, especially when hosting/joining a public server!", aprilFools ? "Sodikm Premium" : "ReBlox", MessageBoxButtons.OK, MessageBoxIcon.Warning);
                                }
                                else if (config[i].Trim() == "Type=RCCService")
                                {
                                    usedRCCService = true;
                                    if (Properties.Settings.Default.RCCServiceFullSupport)
                                    {
                                        RCCService = true;
                                    }
                                    else
                                    {
                                        if (altjoinargument != "") joinargument = altjoinargument;
                                        if (althostargument != "") hostargument = althostargument;
                                        Console.WriteLine("<WARN> This type is not supported. Accepted options: Studio");
                                    }
                                }
                                else if (config[i].Trim() == "Type=Studio")
                                {
                                    usedRCCService = false;
                                    RCCService = false;
                                }
                                else if (config[i].Trim().StartsWith("Type="))
                                {
                                    if (Properties.Settings.Default.RCCServiceFullSupport)
                                    {
                                        Console.WriteLine("<WARN> This type is not supported. Accepted options: Studio RCCService");
                                    }
                                    else
                                    {
                                        Console.WriteLine("<WARN> This type is not supported. Accepted options: Studio");
                                    }
                                }
                                else if (config[i].Trim().StartsWith("VersionForRCCService="))
                                {
                                    versionForRCCService = config[i].Trim().Remove(0, 21);
                                }
                                else if (config[i].Trim() == "UseOldGuestAvatar=true")
                                {
                                    useOldGuestAvatar = true;
                                }
                            }
                            string[] images = Directory.GetFiles(datafolder + @"\clients\" + listBox1.GetItemText(listBox1.SelectedItem) + @"\images");
                            if (images.Length > 0)
                            {
                                int randomchoose = RandomNumber(1, images.Length + 1);
                                currentImage = randomchoose;
                                Size sizecheck = ImageSize.GetDimensions(datafolder + @"\clients\" + listBox1.GetItemText(listBox1.SelectedItem) + @"\images\" + currentImage + ".png");
                                if (sizecheck.Width > 4000 && sizecheck.Height > 4000)
                                {
                                    dirtyImageMain = true;
                                    do
                                    {
                                        Console.WriteLine("<INFO> Skipping " + currentImage + ".png, illegal size!");
                                        currentImage++;
                                        if (File.Exists(datafolder + @"\clients\" + listBox1.GetItemText(listBox1.SelectedItem) + @"\images\" + currentImage + ".png") == false) currentImage = 1;
                                        sizecheck = ImageSize.GetDimensions(datafolder + @"\clients\" + listBox1.GetItemText(listBox1.SelectedItem) + @"\images\" + currentImage + ".png");
                                        if (sizecheck.Width <= 4000 && sizecheck.Height <= 4000)
                                        {
                                            dirtyImageMain = false;
                                        }
                                    } while (dirtyImageMain);
                                }
                                if (useNewImageFadeForClients == false)
                                {
                                    pictureBox1.Visible = true;
                                    pictureBox1.ImageLocation = images[randomchoose - 1];
                                    pictureBox1.Image = Image.FromFile(images[randomchoose - 1]);
                                }
                                randomchoose = 0;

                            }
                            else
                            {
                                pictureBox1.Visible = false;
                            }
                            if (useNewImageFadeForClients)
                            {
                                fadeImage = false;
                                fadeImageTimer.Stop();
                                fadeImageTimer.Interval = 5000;
                                opacity = 0.0F;
                                if (imageFromFade != null) imageFromFade.Dispose();
                                if (imageToFade != null) imageToFade.Dispose();
                                panel7.Invalidate();
                                fadeImageTimer.Start();
                            }
                            else
                            {
                                timer1.Stop();
                                timer1.Start();
                            }
                            images = null;
                        }
                        else
                        {
                            MessageBox.Show("Config file failed to load!", "Config Error", MessageBoxButtons.OK, MessageBoxIcon.Error);
                        }

                    }
                }
            }
            catch
            {
                Console.WriteLine(e);
                MessageBox.Show("Something went wrong while trying to get the client or the client you are trying to pick doesn't exist.", "ReBlox", MessageBoxButtons.OK, MessageBoxIcon.Error);
            }
        }

        private void loadConfigFromClient(string client)
        {
            if (File.Exists(datafolder + @"\clients\" + client + @"\ReBlox.ini"))
            {
                string[] config = File.ReadAllLines(datafolder + @"\clients\" + client + @"\ReBlox.ini");
                if (config[0] == "[Reblox]")
                {
                    placeid = -1;
                    UseJoinJSONLink = false;
                    useIPForwarder = false;
                    ReserveAssetIdForMap = false;
                    useNewRoblox = false;
                    useOldSignature = false;
                    useOldAssetFormat = false;
                    dontLoadMapFromArgument = false;
                    RCCService = false;
                    usedRCCService = false;
                    althostargument = "";
                    altjoinargument = "";
                    versionForRCCService = "";
                    useOldGuestAvatar = false;
                    for (int i = 0; i < config.Length; i++)
                    {
                        if (config[i].Trim().StartsWith("JoinArgument=\""))
                        {
                            string[] splited = config[i].Trim().Split(new char[] { '=' }, 2);
                            joinargument = splited[1].Remove(0, 1).Remove(splited[1].Length - 2, 1);
                        }
                        else if (config[i].Trim().StartsWith("HostArgument=\""))
                        {
                            string[] splited = config[i].Trim().Split(new char[] { '=' }, 2);
                            hostargument = splited[1].Remove(0, 1).Remove(splited[1].Length - 2, 1);
                        }
                        else if (config[i].Trim().StartsWith("AltJoinArgument=\""))
                        {
                            string[] splited = config[i].Trim().Split(new char[] { '=' }, 2);
                            altjoinargument = splited[1].Remove(0, 1).Remove(splited[1].Length - 2, 1);
                        }
                        else if (config[i].Trim().StartsWith("AltHostArgument=\""))
                        {
                            string[] splited = config[i].Trim().Split(new char[] { '=' }, 2);
                            althostargument = splited[1].Remove(0, 1).Remove(splited[1].Length - 2, 1);
                        }
                        else if (config[i].Trim() == "UseJoinScript=true")
                        {
                            UseJoinJSONLink = true;
                        }
                        else if (config[i].Trim() == "UseJoinScript=false")
                        {
                            UseJoinJSONLink = false;
                        }
                        else if (config[i].Trim() == "UseIPForwarder=true")
                        {
                            useIPForwarder = true;
                        }
                        else if (config[i].Trim() == "UseIPForwarder=false")
                        {
                            useIPForwarder = false;
                        }
                        else if (config[i].Trim().StartsWith("PlaceId="))
                        {
                            if (int.TryParse(config[i].Trim().Replace("PlaceId=", ""), out _) == true)
                            {
                                placeid = int.Parse(config[i].Trim().Replace("PlaceId=", ""));
                            }
                        }
                        else if (config[i].Trim() == "UsePlaceAsAsset=true")
                        {
                            if (placeid > -1)
                            {
                                ReserveAssetIdForMap = true;
                            }
                        }
                        else if (config[i].Trim() == "UsePlaceAsAsset=false")
                        {
                            ReserveAssetIdForMap = false;
                            placeid = -1;
                        }
                        else if (config[i].Trim() == "UseNewRobloxName=true")
                        {
                            useNewRoblox = true;
                        }
                        else if (config[i].Trim() == "UseOldSignature=true")
                        {
                            useOldSignature = true;
                        }
                        else if (config[i].Trim() == "UseOldAssetFormat=true")
                        {
                            useOldAssetFormat = true;
                        }
                        else if (config[i].Trim() == "DontLoadMapFromArgument=true")
                        {
                            dontLoadMapFromArgument = true;
                        }
                        else if (config[i].Trim() == "HasSecurityVulnerability=true")
                        {
                            MessageBox.Show("This client version that you have selected appears to have security vulnerabilities, which could put your PC at risk! Please be careful when using this client, especially when hosting/joining a public server!", aprilFools ? "Sodikm Premium" : "ReBlox", MessageBoxButtons.OK, MessageBoxIcon.Warning);
                        }
                        else if (config[i].Trim() == "Type=RCCService")
                        {
                            usedRCCService = true;
                            if (Properties.Settings.Default.RCCServiceFullSupport)
                            {
                                RCCService = true;
                            }
                            else
                            {
                                if (altjoinargument != "") joinargument = altjoinargument;
                                if (althostargument != "") hostargument = althostargument;
                                Console.WriteLine("<WARN> This type is not supported. Accepted options: Studio");
                            }
                        }
                        else if (config[i].Trim() == "Type=Studio")
                        {
                            usedRCCService = false;
                            RCCService = false;
                        }
                        else if (config[i].Trim().StartsWith("Type="))
                        {
                            if (Properties.Settings.Default.RCCServiceFullSupport)
                            {
                                Console.WriteLine("<WARN> This type is not supported. Accepted options: Studio RCCService");
                            }
                            else
                            {
                                Console.WriteLine("<WARN> This type is not supported. Accepted options: Studio");
                            }
                        }
                        else if (config[i].Trim().StartsWith("VersionForRCCService="))
                        {
                            versionForRCCService = config[i].Trim().Remove(0, 21);
                        }
                        else if (config[i].Trim() == "UseOldGuestAvatar=true")
                        {
                            useOldGuestAvatar = true;
                        }
                    }

                }
            }
        }

        private void button7_Click(object sender, EventArgs e)
        {
            if (smartHostDetector())
            {
                if (IsAdministrator())
                {
                    smartHostRemove();
                }
                else
                {
                    try
                    {
                        ProcessStartInfo ps = new ProcessStartInfo() { UseShellExecute = true, FileName = Application.ExecutablePath, Verb = "runas" };
                        Process.Start(ps);
                        Application.Exit();
                    }
                    catch
                    {
                        MessageBox.Show("Something went wrong while trying to run the launcher as administrator! Please run the launcher manually as administrator.", aprilFools ? "Sodikm Premium" : "ReBlox", MessageBoxButtons.OK, MessageBoxIcon.Error);
                    }
                }
            }
            else
            {
                MessageBox.Show("It looks like either you reverted it before or never edited it!", "hosts File", MessageBoxButtons.OK, MessageBoxIcon.Information);
            }
        }

