                                inventory = { },
                                base64FullBody = "",
                                base64HeadShot = ""
                            };
                        }
                        else
                        {
                            List<AssetData> data = new List<AssetData>();
                            data.Add(new AssetData { id = 8561741 });
                            data.Add(new AssetData { id = 48474294 });
                            jsondata = new AvatarType
                            {
                                bodyType = "R6",
                                asset = data,
                                colors = new BodyColors { headColor = 1, leftArmColor = 1003, leftLegColor = 1003, rightArmColor = 1003, rightLegColor = 1003, torsoColor = 27 },
                                inventory = { },
                                base64FullBody = "",
                                base64HeadShot = ""
                            };
                        }
                    }
                    else
                    {
                        if (guestAvatar == "boy")
                        {
                            List<AssetData> data = new List<AssetData>();
                            data.Add(new AssetData { id = 451223307 });
                            data.Add(new AssetData { id = 451224215 });
                            data.Add(new AssetData { id = 451221329 });
                            jsondata = new AvatarType
                            {
                                bodyType = "R6",
                                asset = data,
                                colors = new BodyColors { headColor = 1, leftArmColor = 1, leftLegColor = 102, rightArmColor = 1, rightLegColor = 102, torsoColor = 199 },
                                inventory = { },
                                base64FullBody = "",
                                base64HeadShot = ""
                            };
                        }
                        else
                        {
                            List<AssetData> data = new List<AssetData>();
                            data.Add(new AssetData { id = 451223307 });
                            data.Add(new AssetData { id = 451224215 });
                            data.Add(new AssetData { id = 451220849 });
                            jsondata = new AvatarType
                            {
                                bodyType = "R6",
                                asset = data,
                                colors = new BodyColors { headColor = 1, leftArmColor = 1, leftLegColor = 102, rightArmColor = 1, rightLegColor = 102, torsoColor = 199 },
                                inventory = { },
                                base64FullBody = "",
                                base64HeadShot = ""
                            };
                        }
                    }
                }
                else
                {
                    if (Properties.Settings.Default.ClothesArray.Length > 0)
                    {
                        List<AssetData> data = new List<AssetData>();
                        foreach (var assetid in Properties.Settings.Default.ClothesArray.Split('|'))
                        {
                            data.Add(new AssetData { id = ulong.Parse(assetid) });
                        }
                        jsondata = new AvatarType
                        {
                            bodyType = Properties.Settings.Default.avatarR15 ? "R15" : "R6",
                            asset = data,
                            colors = new BodyColors { headColor = Properties.Settings.Default.HeadColor, leftArmColor = Properties.Settings.Default.LeftArmColor, leftLegColor = Properties.Settings.Default.LeftLegColor, rightArmColor = Properties.Settings.Default.RightArmColor, rightLegColor = Properties.Settings.Default.RightLegColor, torsoColor = Properties.Settings.Default.TorsoColor },
                            inventory = Properties.Settings.Default.ClothesArray.Split('|'),
                            base64FullBody = Properties.Settings.Default.RenderAvatarExperiment ? Properties.Settings.Default.FullBodyBase64 : "",
                            base64HeadShot = Properties.Settings.Default.RenderAvatarExperiment ? Properties.Settings.Default.HeadshotBase64 : ""
                        };
                    }
                    else
                    {
                        jsondata = new AvatarType
                        {
                            bodyType = Properties.Settings.Default.avatarR15 ? "R15" : "R6",
                            asset = { },
                            colors = new BodyColors { headColor = Properties.Settings.Default.HeadColor, leftArmColor = Properties.Settings.Default.LeftArmColor, leftLegColor = Properties.Settings.Default.LeftLegColor, rightArmColor = Properties.Settings.Default.RightArmColor, rightLegColor = Properties.Settings.Default.RightLegColor, torsoColor = Properties.Settings.Default.TorsoColor },
                            inventory = { },
                            base64FullBody = Properties.Settings.Default.RenderAvatarExperiment ? Properties.Settings.Default.FullBodyBase64 : "",
                            base64HeadShot = Properties.Settings.Default.RenderAvatarExperiment ? Properties.Settings.Default.HeadshotBase64 : ""
                        };
                    }
                }

                try
                {
                    HttpClient client = new HttpClient();

                    client.BaseAddress = new Uri("http://reblox.zip");

                    string result = JsonConvert.SerializeObject(jsondata);
                    var buffer = Encoding.UTF8.GetBytes(result);
                    var byteContent = new ByteArrayContent(buffer);
                    byteContent.Headers.ContentType = new System.Net.Http.Headers.MediaTypeHeaderValue("application/json");
                    if (File.Exists(datafolder + @"\private.txt") && File.Exists(datafolder + @"\private.pem"))
                    {
                        using (RSACryptoServiceProvider RSAalg = new RSACryptoServiceProvider())
                        {
                            RSAalg.ImportCspBlob(Convert.FromBase64String(File.ReadAllText(datafolder + @"\private.txt")));

                            RSAParameters Key = RSAalg.ExportParameters(true);

                            byteContent.Headers.Add("x-token", Convert.ToBase64String(HashAndSignBytes(buffer, Key)));
                        }
                    }
                    HttpResponseMessage response = await client.PostAsync("/v1/avatar/set-avatar?userId=" + (guestMode ? guestUserId : (Properties.Settings.Default.LongUserIdExperiment ? Properties.Settings.Default.UserIdLong : Properties.Settings.Default.UserId)) + "&username=" + (guestMode ? guestUsername : Properties.Settings.Default.username), byteContent);

                    response.Dispose();

                    client.Dispose();

                    buffer = null;
                    jsondata = null;
                    result = "";
                }
                catch
                {
                    // do nothing
                }
            }
        }

        private static byte[] HashAndSignBytes(byte[] DataToSign, RSAParameters Key)
        {
            try
            {
                using (RSACryptoServiceProvider RSAalg = new RSACryptoServiceProvider())
                {
                    RSAalg.ImportParameters(Key);

                    return RSAalg.SignData(DataToSign, SHA1.Create());
                }
            }
            catch (CryptographicException e)
            {
                Console.WriteLine("<ERROR> " + e.Message);
                return null;
            }
        }

