        private void textBox3_KeyDown(object sender, KeyEventArgs e)
        {
            if (e.KeyCode == Keys.Enter)
            {
                if (textBox3.Text.StartsWith("_|WARNING:-DO-NOT-SHARE-THIS.--Sharing-this-will-allow-someone-to-log-in-as-you-and-to-steal-your-ROBUX-and-items.|"))
                {
                    Properties.Settings.Default.ROBLOSECURITY = Convert.ToBase64String(Encoding.UTF8.GetBytes(textBox3.Text));
                    Properties.Settings.Default.Save();
                    MessageBox.Show("Your ROBLOSECURITY is hidden by default, however you can show your ROBLOSECURITY by clicking on the \"Show\" button. Please be careful with your ROBLOSECURITY!", aprilFools ? "Sodikm Premium" : "ReBlox", MessageBoxButtons.OK, MessageBoxIcon.Information);
                }
                else
                {
