        int thumbnailgeneratorchecker = 0;
        Regex successDetector = new Regex(@"ThumbnailGenerator::click\(\) success");
        private async void Roblox_OutputDataReceived(object sender, DataReceivedEventArgs e)
        {
            if (String.IsNullOrEmpty(e.Data) == false)
            {
                RCCServiceString += e.Data;

                thumbnailgeneratorchecker += successDetector.Matches(e.Data).Count;

                if (thumbnailgeneratorchecker == 2)
                {
                    thumbnailgeneratorchecker = 0;
                    await Task.Delay(3000);
                    (sender as Process).Kill();
                }
            }
        }

        private void Roblox_Exited1(object sender, EventArgs e)
        {
            Process[] processesr = Process.GetProcessesByName("RobloxStudioBeta");
            Process[] processesr1 = Process.GetProcessesByName("RobloxPlayerBeta");
            Process[] processesr2 = Process.GetProcessesByName("RCCService");
            if (processesr.Length <= 0 && processesr1.Length <= 0 && processesr2.Length <= 0)
            {
                Process[] processes = Process.GetProcessesByName("node");
                if (processes.Length > 0)
                {
                    foreach (Process process in processes)
                    {
                        if (process.MainModule.FileName == datafolder + @"\tools\node\node.exe")
                        {
                            Console.WriteLine("<INFO> Shutting down the node server");
                            statusText.Invoke(new Action(() => { statusText.Text = "Closing node server..."; }));
                            process.Kill();
                        }
                    }
                }
                if (Properties.Settings.Default.ClearTemp)
                {
                    Console.WriteLine("<INFO> Clearing ROBLOX's temporary files");
                    statusText.Invoke(new Action(() => { statusText.Text = "Clearing temp files..."; }));
                    if (Directory.Exists(Path.GetTempPath() + "Roblox")) Directory.Delete(Path.GetTempPath() + "Roblox", true);
                }
                RemoveGameFiles();
                ClearAssets();
                sha1assets.Clear();
            }
            if (File.Exists(datafolder + @"\tools\RCCServiceRenderer\gameserver.txt")) File.Delete(datafolder + @"\tools\RCCServiceRenderer\gameserver.txt");
            button1.Invoke(new Action(() => { button1.Enabled = true; }));
            button2.Invoke(new Action(() => { button2.Enabled = true; }));
            button3.Invoke(new Action(() => { button3.Enabled = true; }));
            button27.Invoke(new Action(() => { button27.Enabled = true; }));
            statusText.Invoke(new Action(() => { statusText.Visible = false; }));
            rendering = false;

            Regex regexp = new Regex(@"\[fullbodyimg:(.*?)]");
            Regex regexp2 = new Regex(@"\[headshot:(.*?)]");

            Match matches1 = regexp.Match(RCCServiceString);
            if (matches1.Success == true && matches1.Groups.Count > 0)
            {
                Properties.Settings.Default.FullBodyBase64 = matches1.Groups[1].Value;
            }
            Match matches2 = regexp2.Match(RCCServiceString);
            if (matches2.Success == true && matches2.Groups.Count > 0)
            {
                //Headshot is broken for now...
                //Properties.Settings.Default.HeadshotBase64 = matches2.Groups[1].Value;
                Properties.Settings.Default.HeadshotBase64 = "";
            }

            if (Properties.Settings.Default.FullBodyBase64 != String.Empty)
            {
                using (MemoryStream stream = new MemoryStream(Convert.FromBase64String(Properties.Settings.Default.FullBodyBase64)))
                {
                    pictureBox3.Image = Image.FromStream(stream);
                }
            }
            Properties.Settings.Default.Save();
            RCCServiceString = "";
        }

